# ========== 创建小说和章节 ==========
for novel_data in novels:
    chapters_data = novel_data.pop("chapters")
    book = Book(**novel_data)
    db.add(book)
    db.flush()  # 获取 book.id

    total_words = 0
    for idx, ch in enumerate(chapters_data, start=1):
        word_count = len(ch["content"])
        total_words += word_count
        chapter = Chapter(
            book_id=book.id,
            chapter_number=idx,
            title=ch["title"],
            content=ch["content"],
            word_count=word_count,
        )
        db.add(chapter)

    book.word_count = total_words
    db.commit()
    print(f"已创建小说《{book.title}》，共 {len(chapters_data)} 章，{total_words} 字")

# ========== 创建书架数据 ==========
# 用户1的书架加入书籍 1, 2, 4
bookshelf_items = [
    Bookshelf(user_id=1, book_id=1, current_chapter=2, progress=35.0),
    Bookshelf(user_id=1, book_id=2, current_chapter=1, progress=10.0),
    Bookshelf(user_id=1, book_id=4, current_chapter=3, progress=100.0),
]
db.add_all(bookshelf_items)
db.commit()
print("已为用户1创建书架数据（3本书）")

# 更新书籍的推荐数和阅读数
db.query(Book).filter(Book.id == 1).update(
    {"recommend_count": Book.recommend_count + 100}
)
db.query(Book).filter(Book.id == 2).update(
    {"read_count": Book.read_count + 50}
)
db.commit()

print("\nMock 数据初始化完成！")
print(f"用户数: {db.query(User).count()}")
print(f"书籍数: {db.query(Book).count()}")
print(f"章节数: {db.query(Chapter).count()}")
print(f"书架数: {db.query(Bookshelf).count()}")

db.close()
